// Validar remetente + extrair dados do documento
const msg = $input.first().json;
const body = msg.body || {};
const messages = body.messages || [body];
const m = messages[0] || {};

// Whitelist de numeros autorizados
const WHITELIST = [
  '{{TELEFONE_REDACTED_01}}',   // autorizado 01
  '{{TELEFONE_REDACTED_02}}',   // autorizado 02
  '{{TELEFONE_REDACTED_03}}',   // autorizado 03
  '{{TELEFONE_REDACTED_04}}',   // autorizado 04
  '{{TELEFONE_REDACTED_05}}'    // autorizado 05
];

const from = m.from || m.chat_id || '';
const fromClean = from.replace('@s.whatsapp.net','').replace('@c.us','');
const sender = m.from_name || m.sender?.name || 'Desconhecido';

// Verificar se e documento/PDF
const doc = m.document || null;
const isDocument = m.type === 'document' || !!doc;
if (!isDocument || !doc) return [];

const filename = doc.filename || doc.file_name || 'documento.pdf';
if (!filename.toLowerCase().endsWith('.pdf')) return [];

const mediaUrl = doc.link || doc.url || null;
const mediaId = doc.id || null;

// normaliza: remove tudo que não for dígito
const normalize = (s) => String(s || '').replace(/\D/g, '');

// formato real sanitizado: {{TELEFONE_REDACTED_01}}
const fromRaw = m.from || '';
const fromDigits = normalize(fromRaw);

// WHITELIST deve estar com dígitos puros
const allowed = WHITELIST.map(normalize);

const isAllowed = allowed.includes(fromDigits);

// normaliza nome do arquivo: lowercase + sem acento
const filenameNormalized = String(filename || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

// valida padrão exato:
// ordem_de_servico_{numero}_{cliente}.pdf
const isTargetFile = /^ordem_de_servico_\d+_.+\.pdf$/.test(filenameNormalized);

return [{
  json: {
    from: fromClean,
    sender,
    chatId: m.chat_id || from,
    filename,
    filename_normalized: filenameNormalized,
    mediaUrl,
    mediaId,
    caption: m.caption || '',
    timestamp: m.timestamp || Date.now(),

    is_allowed: isAllowed,
    is_target_file: isTargetFile,

    from_raw: fromRaw,
    from_digits: fromDigits,
  }
}];
